#include<bits/stdc++.h>
using namespace std;
string s;
void dfs(int x,int y){
    if(y>x){dfs(x,(x+y)/2);dfs((x+y+1)/2,y);}    
    bool flagB=true,flagI=true;
    for(int i=x;i<=y;i++){
        if(s[i]=='1')flagB=false;
        else if(s[i]=='0')flagI=false;
    }
    if(flagB)cout<<'B';
	else if(flagI)cout<<'I';
	else cout<<'F';
}
int main(void) {
    int n;
    cin>>n>>s;
    dfs(0,(1<<n)-1);
    return false;
}
